class InputValidator:
    MAX_STRING_LENGTH = 10000
    MAX_NUMERIC_VALUE = 1e15
    ALLOWED_FIELD_PATTERN = re.compile(r'^[a-zA-Z0-9_\-\.]+$')
    
    @staticmethod
    def validate_string(value: str, field_name: str, max_length: int = None) -> str:
        if not isinstance(value, str):
            raise ValidationError(f"{field_name} must be a string")
        
        max_len = max_length or InputValidator.MAX_STRING_LENGTH
        if len(value) > max_len:
            raise ValidationError(f"{field_name} exceeds maximum length of {max_len}")
        
        return value
    
    @staticmethod
    def validate_alphanumeric(value: str, field_name: str) -> str:
        value = InputValidator.validate_string(value, field_name)
        if not InputValidator.ALLOWED_FIELD_PATTERN.match(value):
            raise ValidationError(f"{field_name} contains invalid characters")
        return value
    
    @staticmethod
    def validate_numeric(value: float, field_name: str, min_val: float = None, max_val: float = None) -> float:
        if not isinstance(value, (int, float)):
            raise ValidationError(f"{field_name} must be numeric")
        
        if abs(value) > InputValidator.MAX_NUMERIC_VALUE:
            raise ValidationError(f"{field_name} value too large")
        
        if min_val is not None and value < min_val:
            raise ValidationError(f"{field_name} below minimum value")
        
        if max_val is not None and value > max_val:
            raise ValidationError(f"{field_name} exceeds maximum value")
        
        return value
    
    @staticmethod
    def validate_enum(value: str, allowed_values: set, field_name: str) -> str:
        value = InputValidator.validate_string(value, field_name, max_length=100)
        if value not in allowed_values:
            raise ValidationError(f"{field_name} has invalid value")
        return value


class SecureTokenManager:
    def __init__(self):
        self._valid_tokens = {}
        self._token_permissions = {}
    
    def create_token(self, user_id: str, permissions: set) -> str:
        token = secrets.token_urlsafe(32)
        token_hash = hashlib.sha256(token.encode()).hexdigest()
        self._valid_tokens[token_hash] = {
            'user_id': user_id,
            'created_at': time.time(),
            'permissions': permissions
        }
        return token
    
    def validate_token(self, token: str) -> AuthContext:
        if not token or not isinstance(token, str):
            raise AuthenticationError("Invalid token format")
        
        token_hash = hashlib.sha256(token.encode()).hexdigest()
        
        if token_hash not in self._valid_tokens:
            logger.warning("Authentication failed: invalid token")
            raise AuthenticationError("Invalid token")
        
        token_data = self._valid_tokens[token_hash]
        
        return AuthContext(
            user_id=token_data['user_id'],
            roles=set(),
            permissions=token_data['permissions']
        )
    
    def revoke_token(self, token: str):
        token_hash = hashlib.sha256(token.encode()).hexdigest()
        self._valid_tokens.pop(token_hash, None)


class AuthorizationManager:
    @staticmethod
    def check_permission(auth_context: AuthContext, required_permission: Permission):
        if required_permission.value not in auth_context.permissions:
            logger.warning(f"Authorization failed for user {auth_context.user_id}")
            raise AuthorizationError(f"Insufficient permissions")


